function getUsuarioLogado() {
    const dados = sessionStorage.getItem("tracklist_logado");
    return dados ? JSON.parse(dados) : null;
}
 
function getChaveFavoritos(usuarioId) {
    return `favoritos_${usuarioId}`;
}
 
function getFavoritos(usuarioId) {
    const chave = getChaveFavoritos(usuarioId);
    return JSON.parse(localStorage.getItem(chave)) || [];
}
 
function isFavoritado(albumId, usuarioId) {
    const id = Number(albumId);
    return getFavoritos(usuarioId).map(Number).includes(id);
}
 
function toggleFavorito(albumId, usuarioId) {
    const chave = getChaveFavoritos(usuarioId);
    const id    = Number(albumId);
    let favoritos = getFavoritos(usuarioId).map(Number);
 
    if (favoritos.includes(id)) {
        favoritos = favoritos.filter(f => f !== id);
    } else {
        favoritos.push(id);
    }
 
    localStorage.setItem(chave, JSON.stringify(favoritos));
}
 
function heartSVG(preenchido) {
    const fill = preenchido ? "#1a1a1a" : "none";
    return `
        <svg xmlns="http://www.w3.org/2000/svg"
             width="18" height="18"
             viewBox="0 0 24 24"
             fill="${fill}"
             stroke="#1a1a1a"
             stroke-width="2"
             stroke-linecap="round"
             stroke-linejoin="round">
            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
        </svg>
    `;
}
 
function createAlbumCard(album) {
    const usuario = getUsuarioLogado();
    const favoritado = usuario ? isFavoritado(album.id, usuario.id || usuario.email) : false;
 
    const col = document.createElement("div");
    col.classList.add("col-12", "col-md-6", "col-lg-3");
 
    const card = document.createElement("div");
    card.classList.add("card", "rounded-0", "h-100");

    const imgWrapper = document.createElement("div");
    imgWrapper.style.position = "relative";
 
    const img = document.createElement("img");
    img.src = album.imagem_principal;
    img.classList.add("card-img-top");

    const btnFav = document.createElement("button");
    btnFav.classList.add("btn-favoritar");
    btnFav.setAttribute("aria-label", favoritado ? "Remover dos favoritos" : "Adicionar aos favoritos");
    btnFav.setAttribute("data-album-id", album.id);
    btnFav.innerHTML = heartSVG(favoritado);
 
    btnFav.addEventListener("click", (e) => {
        e.preventDefault();
        e.stopPropagation();
 
        const usuarioAtual = getUsuarioLogado();
 
        if (!usuarioAtual) {
            mostrarMensagemLogin();
            return;
        }
 
        const userId = usuarioAtual.id || usuarioAtual.email;
        toggleFavorito(album.id, userId);
 
        const agora = isFavoritado(album.id, userId);
        btnFav.innerHTML = heartSVG(agora);
        btnFav.setAttribute("aria-label", agora ? "Remover dos favoritos" : "Adicionar aos favoritos");
    });
 
    imgWrapper.appendChild(img);
    imgWrapper.appendChild(btnFav);
 
    const cardBody = document.createElement("div");
    cardBody.classList.add("card-body");
 
    const title = document.createElement("h5");
    title.classList.add("card-title", "fw-bold");
    title.textContent = album.nome;
 
    const artist = document.createElement("p");
    artist.classList.add("card-text", "text-secondary");
    artist.textContent = album.artista;
 
    const genre = document.createElement("span");
    genre.classList.add("badge", "text-bg-dark", "rounded-0", "mb-3");
    genre.textContent = album.genero;
 
    const button = document.createElement("a");
    button.classList.add("btn", "btn-light", "rounded-0");
    button.textContent = "Ver álbum";
    button.href = `detalhes.html?id=${album.id}`;
 
    cardBody.appendChild(title);
    cardBody.appendChild(artist);
    cardBody.appendChild(genre);
    cardBody.appendChild(button);
 
    card.appendChild(imgWrapper);
    card.appendChild(cardBody);
    col.appendChild(card);
 
    return col;
}
 
function mostrarMensagemLogin() {
    if (document.getElementById("toast-login")) return;
 
    const toast = document.createElement("div");
    toast.id = "toast-login";
    toast.innerHTML = `
        <span>Faça <a href="index.html">login</a> para favoritar álbuns.</span>
        <button onclick="this.parentElement.remove()" aria-label="Fechar">✕</button>
    `;
    toast.style.cssText = `
        position: fixed;
        bottom: 1.5rem;
        left: 50%;
        transform: translateX(-50%);
        background: #1a1a1a;
        color: #fff;
        padding: .75rem 1.25rem;
        display: flex;
        align-items: center;
        gap: 1rem;
        font-family: 'DM Sans', sans-serif;
        font-size: .85rem;
        z-index: 9999;
        border-radius: 0;
        white-space: nowrap;
        box-shadow: 0 4px 12px rgba(0,0,0,.2);
    `;
    toast.querySelector("a").style.cssText = "color:#f5f0ea; text-underline-offset:3px;";
    toast.querySelector("button").style.cssText = `
        background: none;
        border: none;
        color: #aaa;
        cursor: pointer;
        font-size: 1rem;
        line-height: 1;
        padding: 0;
    `;
 
    document.body.appendChild(toast);
    setTimeout(() => toast.remove(), 4000);
}
 
function getTodosAlbuns() {
    const sessao  = sessionStorage.getItem("tracklist_logado");
    const usuario = sessao ? JSON.parse(sessao) : null;
    const userId  = usuario ? (usuario.id || usuario.email) : null;
    const chave   = userId ? "albuns_" + userId : null;

    if (chave) {
        const cadastrados = JSON.parse(localStorage.getItem(chave)) || [];
        if (cadastrados.length > 0) return cadastrados;
    }

    return itens.albuns;
}
 
const albumList = document.getElementById("album-list");

function renderFiltros() {
    const container = document.getElementById("filtros");
    if (!container) return;
 
    const todos   = getTodosAlbuns();

    const mapaGeneros = new Map();
    todos.forEach(album => {
        if (!album.genero) return;
        const chave = album.genero.trim().toLowerCase();
        if (!mapaGeneros.has(chave)) {
            mapaGeneros.set(chave, album.genero.trim());
        }
    });
 
    const generos = Array.from(mapaGeneros.values()).sort();

    container.innerHTML = "";

    const btnTodos = document.createElement("button");
    btnTodos.classList.add("filtro-btn", "active");
    btnTodos.setAttribute("data-genero", "TODOS");
    btnTodos.textContent = "TODOS";
    container.appendChild(btnTodos);

    generos.forEach(genero => {
        const btn = document.createElement("button");
        btn.classList.add("filtro-btn");
        btn.setAttribute("data-genero", genero);
        btn.textContent = genero.toUpperCase();
        container.appendChild(btn);
    });

    container.querySelectorAll(".filtro-btn").forEach(botao => {
        botao.addEventListener("click", () => {
            container.querySelectorAll(".filtro-btn").forEach(b => b.classList.remove("active"));
            botao.classList.add("active");
            renderAlbums(botao.getAttribute("data-genero"));
        });
    });
}

function renderAlbums(filtro) {
    albumList.innerHTML = "";
 
    const todos = getTodosAlbuns();
 
    const albumsFiltrados = filtro === "TODOS"
        ? todos
        : todos.filter(album =>
            album.genero && album.genero.toLowerCase().includes(filtro.toLowerCase())
        );
 
    if (albumsFiltrados.length === 0) {
        albumList.innerHTML = `<p class="sem-resultados">Nenhum álbum encontrado para este gênero.</p>`;
        return;
    }
 
    albumsFiltrados.forEach(album => {
        albumList.appendChild(createAlbumCard(album));
    });
}


renderFiltros();
renderAlbums("TODOS");

const campoBusca = document.getElementById("busca-album");

if (campoBusca) {
    campoBusca.addEventListener("input", () => {
        const termo = campoBusca.value.trim().toLowerCase();

        const filtroAtivo = document.querySelector(".filtro-btn.active");
        const generoAtivo = filtroAtivo ? filtroAtivo.getAttribute("data-genero") : "TODOS";

        albumList.innerHTML = "";

        const todos = getTodosAlbuns();

        const resultado = todos.filter(album => {
            const matchGenero = generoAtivo === "TODOS"
                || (album.genero && album.genero.toLowerCase().includes(generoAtivo.toLowerCase()));

            const matchBusca = !termo
                || album.nome.toLowerCase().includes(termo)
                || album.artista.toLowerCase().includes(termo);

            return matchGenero && matchBusca;
        });

        if (resultado.length === 0) {
            albumList.innerHTML = `<p class="sem-resultados">Nenhum álbum encontrado.</p>`;
            return;
        }

        resultado.forEach(album => albumList.appendChild(createAlbumCard(album)));
    });
}